var surah069 = {
  number: 69,
  nameArabic: "al-Haqqah",
  nameEnglish: "Al-Haqqah",
  meaning: "The Reality",
  totalAyahs: 52,
  ayahs: [
    { number: 1, arabic: "ٱلْحَآقَّةُ", transliteration: "Alhaqqatu", transliterationB: "Al haaaqqah", english: "The Sure Reality", romanUrdu: "Honi shudhni ! (indubitable) [sach-much honay wali]" },
    { number: 2, arabic: "مَا ٱلْحَآقَّةُ", transliteration: "Ma alhaqqatu", transliterationB: "Mal haaaqqah", english: "What is the Sure Reality", romanUrdu: "Kya hai woh honi shudni (indubitable)" },
    { number: 3, arabic: "وَمَآ أَدْرَىٰكَ مَا ٱلْحَآقَّةُ", transliteration: "Wama adraka ma alhaqqatu", transliterationB: "Wa maaa adraaka mal haaaqqah", english: "And what will make thee realise what the Sure Reality is", romanUrdu: "Aur tum kya jaano ke woh kya hai honi shudhni (indubitable)" },
    { number: 4, arabic: "كَذَّبَتْ ثَمُودُ وَعَادٌۢ بِٱلْقَارِعَةِ", transliteration: "Kaththabat thamoodu waAAadun bialqariAAati", transliterationB: "Kazzabat samoodu wa 'Aadum bil qaari'ah", english: "The Thamud and the 'Ad People (branded) as false the Stunning Calamity", romanUrdu: "Samood aur Aad ne us achanak toot padne wali aafat ko jhutlaya" },
    { number: 5, arabic: "فَأَمَّا ثَمُودُ فَأُهْلِكُوا۟ بِٱلطَّاغِيَةِ", transliteration: "Faamma thamoodu faohlikoo bialttaghiyati", transliterationB: "Fa-ammaa Samoodu fauhlikoo bittaaghiyah", english: "But the Thamud,- they were destroyed by a terrible Storm of thunder and lightning", romanUrdu: "To Samood ek sakht haadse mein halaaq kiye gaye" },
    { number: 6, arabic: "وَأَمَّا عَادٌۭ فَأُهْلِكُوا۟ بِرِيحٍۢ صَرْصَرٍ عَاتِيَةٍۢ", transliteration: "Waamma AAadun faohlikoo bireehin sarsarin AAatiyatin", transliterationB: "Wa ammaa 'Aadun fa uhlikoo bireehin sarsarin 'aatiyah", english: "And the 'Ad, they were destroyed by a furious Wind, exceedingly violent", romanUrdu: "Aur Aad ek badi shadeed toofani aandhi(storm) se tabah kardiye gaye" },
    { number: 7, arabic: "سَخَّرَهَا عَلَيْهِمْ سَبْعَ لَيَالٍۢ وَثَمَٰنِيَةَ أَيَّامٍ حُسُومًۭا فَتَرَى ٱلْقَوْمَ فِيهَا صَرْعَىٰ كَأَنَّهُمْ أَعْجَازُ نَخْلٍ خَاوِيَةٍۢ", transliteration: "Sakhkharaha AAalayhim sabAAa layalin wathamaniyata ayyamin husooman fatara alqawma feeha sarAAa kaannahum aAAjazu nakhlin khawiyatun", transliterationB: "Sakhkharahaa 'alaihim sab'a la yaalinw wa samaaniyata ayyaamin husooman fataral qawma feehaa sar'aa ka annahum a'jaazu nakhlin khaawiyah", english: "He made it rage against them seven nights and eight days in succession: so that thou couldst see the (whole) people lying prostrate in its (path), as they had been roots of hollow palm-trees tumbled down", romanUrdu: "Allah taala ne usko musalsal saat (seven) raat aur aath (eight) din unpar musallat rakkha (tum wahan hotey to) dekhte ke woh wahan is tarah pachade paday jaise woh khajoor ke boseeda (rotten) taney (trunks) hon" },
    { number: 8, arabic: "فَهَلْ تَرَىٰ لَهُم مِّنۢ بَاقِيَةٍۢ", transliteration: "Fahal tara lahum min baqiyatin", transliterationB: "Fahal taraa lahum mim baaqiyah", english: "Then seest thou any of them left surviving", romanUrdu: "Ab kya unmein se koi tumhein baki nazar aata hai" },
    { number: 9, arabic: "وَجَآءَ فِرْعَوْنُ وَمَن قَبْلَهُۥ وَٱلْمُؤْتَفِكَٰتُ بِٱلْخَاطِئَةِ", transliteration: "Wajaa firAAawnu waman qablahu waalmutafikatu bialkhatiati", transliterationB: "Wa jaaa'a Firawnu wa man qablahoo wal mu'tafikaatu bilhaati'ah", english: "And Pharaoh, and those before him, and the Cities Overthrown, committed habitual Sin", romanUrdu: "Aur isi khata-e-azeem ka irtiqaab Firoun aur ussey pehle ke logon ne aur talpat (overturned) ho janey wali bastiyon ne kiya" },
    { number: 10, arabic: "فَعَصَوْا۟ رَسُولَ رَبِّهِمْ فَأَخَذَهُمْ أَخْذَةًۭ رَّابِيَةً", transliteration: "FaAAasaw rasoola rabbihim faakhathahum akhthatan rabiyatan", transliterationB: "Fa'ansaw Rasoola Rabbihim fa akhazahum akhzatar raabiyah", english: "And disobeyed (each) the messenger of their Lord; so He punished them with an abundant Penalty", romanUrdu: "Un sab ne apne Rubb ke Rasool ki baat na maani to usne unko bade sakhti ke saath pakda" },
    { number: 11, arabic: "إِنَّا لَمَّا طَغَا ٱلْمَآءُ حَمَلْنَٰكُمْ فِى ٱلْجَارِيَةِ", transliteration: "Inna lamma tagha almao hamalnakum fee aljariyati", transliterationB: "Innaa lammaa taghal maaa'u hamalnaakum fil jaariyah", english: "We, when the water (of Noah's Flood) overflowed beyond its limits, carried you (mankind), in the floating (Ark)", romanUrdu: "Jab pani ka toofan hadd se guzar gaya to humne tumko kashti mein sawar kardiya tha" },
    { number: 12, arabic: "لِنَجْعَلَهَا لَكُمْ تَذْكِرَةًۭ وَتَعِيَهَآ أُذُنٌۭ وَٰعِيَةٌۭ", transliteration: "LinajAAalaha lakum tathkiratan wataAAiyaha othunun waAAiyatun", transliterationB: "Linaj'alahaa lakum tazki ratanw-wa ta'iyahaa unzununw waa'iyah", english: "That We might make it a Message unto you, and that ears (that should hear the tale and) retain its memory should bear its (lessons) in remembrance", romanUrdu: "Taa-ke is waqiye ko tumhare liye ek sabaq-aamoz yaadgaar bana dein aur yaad rakhne waley kaan iski yaad mehfooz rakkhein" },
    { number: 13, arabic: "فَإِذَا نُفِخَ فِى ٱلصُّورِ نَفْخَةٌۭ وَٰحِدَةٌۭ", transliteration: "Faitha nufikha fee alssoori nafkhatun wahidatun", transliterationB: "Fa izaa nufikha fis soori nafkhatunw waahidah", english: "Then, when one blast is sounded on the Trumpet", romanUrdu: "Phir jab ek dafa sur mein phoonk maar di jayegi" },
    { number: 14, arabic: "وَحُمِلَتِ ٱلْأَرْضُ وَٱلْجِبَالُ فَدُكَّتَا دَكَّةًۭ وَٰحِدَةًۭ", transliteration: "Wahumilati alardu waaljibalu fadukkata dakkatan wahidatan", transliterationB: "Wa humilatil ardu wal jibaalu fadukkataa dakkatanw waahidah", english: "And the earth is moved, and its mountains, and they are crushed to powder at one stroke", romanUrdu: "Aur zameen aur pahadon ko utha kar ek hi chot mein reza reza kardiya jayega" },
    { number: 15, arabic: "فَيَوْمَئِذٍۢ وَقَعَتِ ٱلْوَاقِعَةُ", transliteration: "Fayawmaithin waqaAAati alwaqiAAatu", transliterationB: "Fa yawma'izinw waqa'atil waaqi'ah", english: "On that Day shall the (Great) Event come to pass", romanUrdu: "Us roz woh honay wala waqiya pesh aa jayega" },
    { number: 16, arabic: "وَٱنشَقَّتِ ٱلسَّمَآءُ فَهِىَ يَوْمَئِذٍۢ وَاهِيَةٌۭ", transliteration: "Wainshaqqati alssamao fahiya yawmaithin wahiyatun", transliterationB: "Wanshaqqatis samaaa'u fahiya yawma 'izinw-waahiyah", english: "And the sky will be rent asunder, for it will that Day be flimsy", romanUrdu: "Usdin Aasmaan phatega aur uski bandish dhili padh jayegi" },
    { number: 17, arabic: "وَٱلْمَلَكُ عَلَىٰٓ أَرْجَآئِهَا ۚ وَيَحْمِلُ عَرْشَ رَبِّكَ فَوْقَهُمْ يَوْمَئِذٍۢ ثَمَٰنِيَةٌۭ", transliteration: "Waalmalaku AAala arjaiha wayahmilu AAarsha rabbika fawqahum yawmaithin thamaniyatun", transliterationB: "Wal malaku 'alaaa arjaaa'ihaa; wa yahmilu 'Arsha Rabbika fawqahum yawma'izin samaaniyah", english: "And the angels will be on its sides, and eight will, that Day, bear the Throne of thy Lord above them", romanUrdu: "Farishtey uske atraf-o-jawanib mein hongey aur aat (eight) farishtey us roz tere Rubb ka arsh apne upar uthaye huey hongey" },
    { number: 18, arabic: "يَوْمَئِذٍۢ تُعْرَضُونَ لَا تَخْفَىٰ مِنكُمْ خَافِيَةٌۭ", transliteration: "Yawmaithin tuAAradoona la takhfa minkum khafiyatun", transliterationB: "Yawma'izin tu'radoona laa takhfaa min kum khaafiyah", english: "That Day shall ye be brought to Judgment: not an act of yours that ye hide will be hidden", romanUrdu: "Woh din hoga jab tumlog pesh kiye jaogey, tumhara koi raaz bhi chupa na reh jayega" },
    { number: 19, arabic: "فَأَمَّا مَنْ أُوتِىَ كِتَٰبَهُۥ بِيَمِينِهِۦ فَيَقُولُ هَآؤُمُ ٱقْرَءُوا۟ كِتَٰبِيَهْ", transliteration: "Faamma man ootiya kitabahu biyameenihi fayaqoolu haomu iqraoo kitabiyah", transliterationB: "Fa ammaa man ootiya kitaabahoo biyameenihee fa yaqoolu haaa'umuq ra'oo kitaabiyah", english: "Then he that will be given his Record in his right hand will say: \"Ah here! Read ye my Record", romanUrdu: "Us waqt jiska naam-e-aamal uske seedhey haath mein diya jayega woh kahega “lo dekho, padho mera naam-e-aamal" },
    { number: 20, arabic: "إِنِّى ظَنَنتُ أَنِّى مُلَٰقٍ حِسَابِيَهْ", transliteration: "Innee thanantu annee mulaqin hisabiyah", transliterationB: "Innee zannantu annee mulaaqin hisaabiyah", english: "I did really understand that my Account would (One Day) reach me", romanUrdu: "Main samajhta tha ke mujhey zaroor apna hisaab milne wala hai”" },
    { number: 21, arabic: "فَهُوَ فِى عِيشَةٍۢ رَّاضِيَةٍۢ", transliteration: "Fahuwa fee AAeeshatin radiyatin", transliterationB: "Fahuwa fee 'eeshatir raadiyah", english: "And he will be in a life of Bliss", romanUrdu: "Pas woh dil pasand aish mein hoga" },
    { number: 22, arabic: "فِى جَنَّةٍ عَالِيَةٍۢ", transliteration: "Fee jannatin AAaliyatin", transliterationB: "Fee jannnatin 'aaliyah", english: "In a Garden on high", romanUrdu: "Aali muqaam jannat mein" },
    { number: 23, arabic: "قُطُوفُهَا دَانِيَةٌۭ", transliteration: "Qutoofuha daniyatun", transliterationB: "Qutoofuhaa daaniyah", english: "The Fruits whereof (will hang in bunches) low and near", romanUrdu: "Jiske phalon ke guchhey jhuke padh rahey hongey" },
    { number: 24, arabic: "كُلُوا۟ وَٱشْرَبُوا۟ هَنِيٓـًٔۢا بِمَآ أَسْلَفْتُمْ فِى ٱلْأَيَّامِ ٱلْخَالِيَةِ", transliteration: "Kuloo waishraboo haneean bima aslaftum fee alayyami alkhaliyati", transliterationB: "Kuloo washraboo haneee'am bimaaa aslaftum fil ayyaamil khaliyah", english: "Eat ye and drink ye, with full satisfaction; because of the (good) that ye sent before you, in the days that are gone", romanUrdu: "(Aise logon se kaha jayega) mazey se khao aur pio apne un aamal ke badle jo tumne guzre huey dino mein kiye hain" },
    { number: 25, arabic: "وَأَمَّا مَنْ أُوتِىَ كِتَٰبَهُۥ بِشِمَالِهِۦ فَيَقُولُ يَٰلَيْتَنِى لَمْ أُوتَ كِتَٰبِيَهْ", transliteration: "Waamma man ootiya kitabahu bishimalihi fayaqoolu ya laytanee lam oota kitabiyah", transliterationB: "Wa ammaa man ootiya kitaabahoo bishimaalihee fa yaqoolu yaalaitanee lam oota kitaaabiyah", english: "And he that will be given his Record in his left hand, will say: \"Ah! Would that my Record had not been given to me", romanUrdu: "Aur jiska naam-e-aamal uske bayein (left) haath mein diya jayega woh kahega “ kaash mera aamal nama mujhey na diya gaya hota" },
    { number: 26, arabic: "وَلَمْ أَدْرِ مَا حِسَابِيَهْ", transliteration: "Walam adri ma hisabiyah", transliterationB: "Wa lam adri maa hisaabiyah", english: "And that I had never realised how my account (stood)", romanUrdu: "Aur main na jaanta ke mera hisaab kya hai" },
    { number: 27, arabic: "يَٰلَيْتَهَا كَانَتِ ٱلْقَاضِيَةَ", transliteration: "Ya laytaha kanati alqadiyatu", transliterationB: "Yaa laitahaa kaanatil qaadiyah", english: "Ah! Would that (Death) had made an end of me", romanUrdu: "Kaash meri wahi maut (jo duniya mei aayi thi) faisla-kun hoti" },
    { number: 28, arabic: "مَآ أَغْنَىٰ عَنِّى مَالِيَهْ ۜ", transliteration: "Ma aghna AAannee maliyah", transliterationB: "Maaa aghnaa 'annee maaliyah", english: "Of no profit to me has been my wealth", romanUrdu: "Aaj mera maal mere kuch kaam na aaya" },
    { number: 29, arabic: "هَلَكَ عَنِّى سُلْطَٰنِيَهْ", transliteration: "Halaka AAannee sultaniyah", transliterationB: "Halaka 'annee sultaaniyah", english: "My power has perished from me", romanUrdu: "Mera sara iqtedaar khatam ho gaya" },
    { number: 30, arabic: "خُذُوهُ فَغُلُّوهُ", transliteration: "Khuthoohu faghulloohu", transliterationB: "Khuzoohu faghullooh", english: "(The stern command will say): \"Seize ye him, and bind ye him", romanUrdu: "(hukum hoga) pakdo isey aur iski gardan mei touk daal do" },
    { number: 31, arabic: "ثُمَّ ٱلْجَحِيمَ صَلُّوهُ", transliteration: "Thumma aljaheema salloohu", transliterationB: "Summal Jaheema sallooh", english: "And burn ye him in the Blazing Fire", romanUrdu: "Phir isey jahannum mein jhoonk do" },
    { number: 32, arabic: "ثُمَّ فِى سِلْسِلَةٍۢ ذَرْعُهَا سَبْعُونَ ذِرَاعًۭا فَٱسْلُكُوهُ", transliteration: "Thumma fee silsilatin tharAAuha sabAAoona thiraAAan faoslukoohu", transliterationB: "Summa fee silsilatin zar'uhaa sab'oona ziraa'an faslukooh", english: "Further, make him march in a chain, whereof the length is seventy cubits", romanUrdu: "Phir isko satter(seventy) haath lambi zanjeer mei jakad do" },
    { number: 33, arabic: "إِنَّهُۥ كَانَ لَا يُؤْمِنُ بِٱللَّهِ ٱلْعَظِيمِ", transliteration: "Innahu kana la yuminu biAllahi alAAatheemi", transliterationB: "Innahoo kaana laa yu'minubillaahil 'Azeem", english: "This was he that would not believe in Allah Most High", romanUrdu: "Yeh na Allah buzurg-o-bartar par iman lata tha" },
    { number: 34, arabic: "وَلَا يَحُضُّ عَلَىٰ طَعَامِ ٱلْمِسْكِينِ", transliteration: "Wala yahuddu AAala taAAami almiskeeni", transliterationB: "wa laa yahuddu 'alaa ta'aamil miskeen", english: "And would not encourage the feeding of the indigent", romanUrdu: "Aur na miskeen ko khana khilane ki targeeb deta tha" },
    { number: 35, arabic: "فَلَيْسَ لَهُ ٱلْيَوْمَ هَٰهُنَا حَمِيمٌۭ", transliteration: "Falaysa lahu alyawma hahuna hameemun", transliterationB: "Falaysa lahul yawma haahunaa hameem", english: "So no friend hath he here this Day", romanUrdu: "Lihaza aaj na yahan iska koi yaar-e-gamkhaar hai" },
    { number: 36, arabic: "وَلَا طَعَامٌ إِلَّا مِنْ غِسْلِينٍۢ", transliteration: "Wala taAAamun illa min ghisleenin", transliterationB: "Wa laa ta'aamun illaa min ghisleen", english: "Nor hath he any food except the corruption from the washing of wounds", romanUrdu: "Aur na zakhmon ke dhowan (washing of wounds) ke siwa iske liye koi khana" },
    { number: 37, arabic: "لَّا يَأْكُلُهُۥٓ إِلَّا ٱلْخَٰطِـُٔونَ", transliteration: "La yakuluhu illa alkhatioona", transliterationB: "Laa yaakuluhooo illal khati'oon", english: "Which none do eat but those in sin", romanUrdu: "Jisey khatakaaron (sinners) ke siwa koi nahin khata" },
    { number: 38, arabic: "فَلَآ أُقْسِمُ بِمَا تُبْصِرُونَ", transliteration: "Fala oqsimu bima tubsiroona", transliterationB: "Falaaa uqsimu bimaa tubsiroon", english: "So I do call to witness what ye see", romanUrdu: "Pas nahin, main qasam khata hoon un cheezon ki bhi jo tum dekhte ho" },
    { number: 39, arabic: "وَمَا لَا تُبْصِرُونَ", transliteration: "Wama la tubsiroona", transliterationB: "Wa maa laa tubsiroon", english: "And what ye see not", romanUrdu: "Aur unki bhi jinhein tum nahin dekhte" },
    { number: 40, arabic: "إِنَّهُۥ لَقَوْلُ رَسُولٍۢ كَرِيمٍۢ", transliteration: "Innahu laqawlu rasoolin kareemin", transliterationB: "Innahoo laqawlu Rasoolin kareem", english: "That this is verily the word of an honoured messenger", romanUrdu: "Yeh ek Rasool-e-kareem ka qaul ( speech ) hai" },
    { number: 41, arabic: "وَمَا هُوَ بِقَوْلِ شَاعِرٍۢ ۚ قَلِيلًۭا مَّا تُؤْمِنُونَ", transliteration: "Wama huwa biqawli shaAAirin qaleelan ma tuminoona", transliterationB: "Wa ma huwa biqawli shaa'ir; qaleelam maa tu'minoon", english: "It is not the word of a poet: little it is ye believe", romanUrdu: "Kisi shayar ka qaul nahin hai, tumlog kam hi iman latey ho" },
    { number: 42, arabic: "وَلَا بِقَوْلِ كَاهِنٍۢ ۚ قَلِيلًۭا مَّا تَذَكَّرُونَ", transliteration: "Wala biqawli kahinin qaleelan ma tathakkaroona", transliterationB: "Wa laa biqawli kaahin; qaleelam maa tazakkaroon", english: "Nor is it the word of a soothsayer: little admonition it is ye receive", romanUrdu: "Aur na yeh kisi kaahin(soothsayer) ka qaul hai , tum log kam hi gaur karte ho" },
    { number: 43, arabic: "تَنزِيلٌۭ مِّن رَّبِّ ٱلْعَٰلَمِينَ", transliteration: "Tanzeelun min rabbi alAAalameena", transliterationB: "Tanzeelum mir rabbil 'aalameen", english: "(This is) a Message sent down from the Lord of the Worlds", romanUrdu: "Yeh Rabb-ul alameen ki taraf se nazil huwa hai" },
    { number: 44, arabic: "وَلَوْ تَقَوَّلَ عَلَيْنَا بَعْضَ ٱلْأَقَاوِيلِ", transliteration: "Walaw taqawwala AAalayna baAAda alaqaweeli", transliterationB: "Wa law taqawwala 'alainaa ba'dal aqaaweel", english: "And if the messenger were to invent any sayings in Our name", romanUrdu: "Aur agar is (Nabi) ne khud ghad kar koi baat hamari taraf mansook ki hoti" },
    { number: 45, arabic: "لَأَخَذْنَا مِنْهُ بِٱلْيَمِينِ", transliteration: "Laakhathna minhu bialyameeni", transliterationB: "La-akhaznaa minhu bilyameen", english: "We should certainly seize him by his right hand", romanUrdu: "To hum iska dayan(right) haath padkad letay" },
    { number: 46, arabic: "ثُمَّ لَقَطَعْنَا مِنْهُ ٱلْوَتِينَ", transliteration: "Thumma laqataAAna minhu alwateena", transliterationB: "Summa laqata'naa minhul wateen", english: "And We should certainly then cut off the artery of his heart", romanUrdu: "Aur iski rag-e-gardan (life vein) kaat daalte" },
    { number: 47, arabic: "فَمَا مِنكُم مِّنْ أَحَدٍ عَنْهُ حَٰجِزِينَ", transliteration: "Fama minkum min ahadin AAanhu hajizeena", transliterationB: "Famaa minkum min ahadin'anhu haajizeen", english: "Nor could any of you withhold him (from Our wrath)", romanUrdu: "Phir tum mein se koi (humein)is kaam se rokne wala na hota" },
    { number: 48, arabic: "وَإِنَّهُۥ لَتَذْكِرَةٌۭ لِّلْمُتَّقِينَ", transliteration: "Wainnahu latathkiratun lilmuttaqeena", transliterationB: "Wa innahoo latazkiratul lilmuttaqeen", english: "But verily this is a Message for the Allah-fearing", romanUrdu: "Dar haqeeqat yeh parheizgar logon ke liye ek naseehat hai" },
    { number: 49, arabic: "وَإِنَّا لَنَعْلَمُ أَنَّ مِنكُم مُّكَذِّبِينَ", transliteration: "Wainna lanaAAlamu anna minkum mukaththibeena", transliterationB: "Wa inna lana'lamu anna minkum mukazzibeen", english: "And We certainly know that there are amongst you those that reject (it)", romanUrdu: "Aur hum jante hain ke tum mein se kuch log jhutlane waley hain" },
    { number: 50, arabic: "وَإِنَّهُۥ لَحَسْرَةٌ عَلَى ٱلْكَٰفِرِينَ", transliteration: "Wainnahu lahasratun AAala alkafireena", transliterationB: "Wa innahu lahasratun 'alal kaafireen", english: "But truly (Revelation) is a cause of sorrow for the Unbelievers", romanUrdu: "Aise kafiron ke liye yaqeenan yeh mujeeb-e-hasrat (cause of regret) hai" },
    { number: 51, arabic: "وَإِنَّهُۥ لَحَقُّ ٱلْيَقِينِ", transliteration: "Wainnahu lahaqqu alyaqeeni", transliterationB: "Wa innahoo lahaqqul yaqeen", english: "But verily it is Truth of assured certainty", romanUrdu: "Aur yeh bilkul yaqeeni haqq hai" },
    { number: 52, arabic: "فَسَبِّحْ بِٱسْمِ رَبِّكَ ٱلْعَظِيمِ", transliteration: "Fasabbih biismi rabbika alAAatheemi", transliterationB: "Fasbbih bismi Rabbikal 'Azeem", english: "So glorify the name of thy Lord Most High", romanUrdu: "Pas aey nabi, apne Rubb-e-azeem ke naam ki tasbeeh karo" }
  ]
};
